Value.Calculation:
Let([
ts = GetAsTimestamp ( Get ( CurrentHostTimestamp ) ) ;
d = GetAsDate ( ts ) ;
t = GetAsTime ( ts )
] ;
Year ( d ) & "-" & Right ( "0" & Month ( d ) ; 2 ) & "-" & Right ( "0" & Day ( d ) ; 2 ) & "T" &
Right ( "0" & Hour ( t ) ; 2 ) & ":" & Right ( "0" & Minute ( t ) ; 2 ) & ":" & Right ( "0" & Int ( Seconds ( t ) ) ; 2 ) & "Z"
)

Case (
	Left ( $sql_contracts ; 5 ) = "[MBS]" ;
	"sql_err=" & Left ( $sql_contracts ; 80 ) ;
	"contract_count=" & $contract_count &
	Case ( $contract_count > 0 ;
		"|c0id=" & TrimAll ( GetAsText ( JSONGetElement ( $json_contracts ; "[0].vertrag_id" ) ) ; 1 ; 1 ) &
		"|c0name=" & TrimAll ( GetAsText ( JSONGetElement ( $json_contracts ; "[0].vertrag" ) ) ; 1 ; 1 ) &
		"|c0own=" & TrimAll ( GetAsText ( JSONGetElement ( $json_contracts ; "[0].owner" ) ) ; 1 ; 1 ) ;
		"|c0=none"
	) &
	"|map=" & Left ( Substitute ( $owner_map ; ¶ ; " / " ) ; 120 )
)

Case (
	not IsEmpty ( TrimAll ( GetAsText ( JSONGetElement ( $json_marked ; "[" & $midx & "].owner" ) ) ; 1 ; 1 ) ) ;
	Lower ( Substitute ( TrimAll ( GetAsText ( JSONGetElement ( $json_marked ; "[" & $midx & "].owner" ) ) ; 1 ; 1 ) ; "+" ; "-" ; " " ; "-" ; "&" ; "-" ; "/" ; "-" ; "_" ; "-" ) ) ;
	Lower ( Substitute ( TrimAll ( GetAsText ( MBS("FM.SQL.Field"; $sql_marked; $midx; 2 ) ) ; 1 ; 1 ) ; "+" ; "-" ; " " ; "-" ; "&" ; "-" ; "/" ; "-" ; "_" ; "-" ) )
)
)

MBS("FM.SQL.Execute"; "";
Case (
	$marked_count = 0 ;
	"SELECT \"Vorgang_ID\", \"Vertrag\", \"Art der Erledigung\", \"Datum\", \"Frist\", \"Datei\" FROM \"" & $$FM_VORGAENGE_TABELLE & "\" WHERE 1 = 0" ;
	"SELECT \"Vorgang_ID\", \"Vertrag\", \"Art der Erledigung\", \"Datum\", \"Frist\", \"Datei\" FROM \"" & $$FM_VORGAENGE_TABELLE & "\" WHERE \"Datei\" IS NOT NULL AND lower(trim(\"Vertrag\" || '')) IN (" & Substitute ( $marked_sql_list ; "¶" ; "," ) & ")"
))

Let([ 
  _vid = Case ( Filter ( TrimAll ( GetAsText ( $vertrag_raw ) ; 1 ; 1 ) ; "0123456789" ) = TrimAll ( GetAsText ( $vertrag_raw ) ; 1 ; 1 ) ; GetAsNumber ( $vertrag_raw ) ; "" )
] ;
  Case ( IsEmpty ( _vid ) ; "" ; $base_url & "/rest/v1/vertraege?select=vertragsbesitzer_id&vertrag_id=eq." & _vid )
)

Let([ d = GetValue(Substitute($datum_raw; " "; ""); 1) ];
Case(
IsEmpty(d); "";
PatternCount(d; "-") = 2; Left(d; 10);
PatternCount(d; ".") = 2; Let([
 p1=Position(d;".";1;1); p2=Position(d;".";1;2);
 day=Left(d;p1-1); mon=Middle(d;p1+1;p2-p1-1);
 yr0=GetValue(Substitute(Middle(d;p2+1;99);" ";"");1);
 yr=Case(Length(yr0)=2;"20"&yr0;yr0)
]; yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));
PatternCount(d; "/") = 2; Let([
 p1=Position(d;"/";1;1); p2=Position(d;"/";1;2);
 mon=Left(d;p1-1); day=Middle(d;p1+1;p2-p1-1);
 yr0=GetValue(Substitute(Middle(d;p2+1;99);" ";"");1);
 yr=Case(Length(yr0)=2;"20"&yr0;yr0)
]; yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));
""
))

Let([ d = GetValue(Substitute($frist_raw; " "; ""); 1) ];
Case(
IsEmpty(d); "";
PatternCount(d; "-") = 2; Left(d; 10);
PatternCount(d; ".") = 2; Let([
 p1=Position(d;".";1;1); p2=Position(d;".";1;2);
 day=Left(d;p1-1); mon=Middle(d;p1+1;p2-p1-1);
 yr0=GetValue(Substitute(Middle(d;p2+1;99);" ";"");1);
 yr=Case(Length(yr0)=2;"20"&yr0;yr0)
]; yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));
PatternCount(d; "/") = 2; Let([
 p1=Position(d;"/";1;1); p2=Position(d;"/";1;2);
 mon=Left(d;p1-1); day=Middle(d;p1+1;p2-p1-1);
 yr0=GetValue(Substitute(Middle(d;p2+1;99);" ";"");1);
 yr=Case(Length(yr0)=2;"20"&yr0;yr0)
]; yr&"-"&Right("0"&mon;2)&"-"&Right("0"&day;2));
""
))

JSONSetElement ( "{}" ;
[ "vorgang_id" ; $vorgang_id ; JSONString ] ;
[ "vertragsbesitzer_id" ; $owner_for_row ; JSONString ] ;
[ "vertrag" ; Case ( PatternCount ( "¶" & $marked_list & "¶" ; "¶" & $vertrag_key & "¶" ) > 0 ; $vertrag_raw ; "" ) ; JSONString ] ;
[ "vorgang_art" ; $art ; JSONString ] ;
[ "kurzbeschreibung" ; $art ; JSONString ] ;
[ "datum" ; $datum_iso ; If ( IsEmpty ( $datum_iso ) ; JSONNull ; JSONString ) ] ;
[ "frist" ; $frist_iso ; If ( IsEmpty ( $frist_iso ) ; JSONNull ; JSONString ) ] ;
[ "datei_pfad" ; $storage_path ; JSONString ] ;
[ "sync_state" ; "geaendert" ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "script_name" ; "05_FM_ARCHIVY_SYNC_VORGAENGE_PDF_PUSH_CONTAINER" ; JSONString ] ;
	[ "script_version" ; $script_version ; JSONString ] ;
	[ "owner_id" ; $owner_id ; JSONString ] ;
	[ "status" ; Case ( IsEmpty ( $fehler ) ; "ok" ; "error" ) ; JSONString ] ;
	[ "ok_count" ; $ok ; JSONNumber ] ;
	[ "skip_count" ; $skip ; JSONNumber ] ;
	[ "error_count" ; Case ( IsEmpty ( $fehler ) ; 0 ; ValueCount ( $fehler ) ) ; JSONNumber ] ;
	[ "result_text" ; Left ( $$SYNC_RESULT_PDF ; 9000 ) ; JSONString ] ;
	[ "error_text" ; Left ( $fehler ; 9000 ) ; JSONString ] ;
	[ "needs_review" ; True ; JSONBoolean ] ;
	[ "detail_json" ; JSONSetElement ( "{}" ;
		[ "processed_count" ; If ( IsEmpty ( $anzahl ) ; 0 ; $anzahl ) ; JSONNumber ] ;
		[ "auth_blocked" ; $auth_blocked ; JSONNumber ]
	) ; JSONObject ]
)
